selector_to_html = {"a[href=\"system.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es do Sistema<a class=\"headerlink\" href=\"#system-settings\" title=\"Link to this heading\">#</a></h1><h2>Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"character.html#end-character-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00f5es do Personagem<a class=\"headerlink\" href=\"#end-character-settings\" title=\"Link to this heading\">#</a></h2><p>O caractere final \u00e9 adicionado ap\u00f3s os dados decodificados no formato de dados decodificados + caractere final.</p>", "a[href=\"#yx-290\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><strong>YX-290</strong> \u6709\u7ebf\u626b\u63cf\u67aa\u5feb\u901f\u8bbe\u7f6e\u624b\u518c<a class=\"headerlink\" href=\"#yx-290\" title=\"Link to this heading\">#</a></h1>", "a[href=\"scanmode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Simbologias 2D<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Modo de Escaneo<a class=\"headerlink\" href=\"#scan-mode\" title=\"Link to this heading\">#</a></h1><h2>Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html#d-symbologies\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Simbologias 1D<a class=\"headerlink\" href=\"#d-symbologies\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"barcode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Simbologias<a class=\"headerlink\" href=\"#symbologies\" title=\"Link to this heading\">#</a></h1><h2>Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"scanmode.html#continuous-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modo cont\u00ednuo<a class=\"headerlink\" href=\"#continuous-mode\" title=\"Link to this heading\">#</a></h2><p>O scanner funciona continuamente. Se a verifica\u00e7\u00e3o for bem-sucedida ou o tempo de verifica\u00e7\u00e3o exceder o tempo de trabalho \u00fanico, a verifica\u00e7\u00e3o atual termina. Se o tempo exceder o tempo especificado, a pr\u00f3xima verifica\u00e7\u00e3o \u00e9 ativada automaticamente.</p>", "a[href=\"scanmode.html#auto-sensing-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modo de Detec\u00e7\u00e3o Autom\u00e1tica<a class=\"headerlink\" href=\"#auto-sensing-mode\" title=\"Link to this heading\">#</a></h2><p>No modo de detec\u00e7\u00e3o autom\u00e1tica, o scanner detectar\u00e1 o brilho do ambiente ao redor. Quando o brilho muda, a varredura \u00e9 ativada. A verifica\u00e7\u00e3o termina quando a verifica\u00e7\u00e3o for bem-sucedida ou o tempo de verifica\u00e7\u00e3o exceder o tempo de trabalho \u00fanico. Independentemente de a \u00faltima verifica\u00e7\u00e3o ter sido bem-sucedida ou falhada, o brilho do ambiente ao redor ser\u00e1 detectado novamente.</p>", "a[href=\"scanmode.html#key-trigger-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modo de disparo de chaves<a class=\"headerlink\" href=\"#key-trigger-mode\" title=\"Link to this heading\">#</a></h2><p>Pressione o bot\u00e3o para acionar a varredura e solte o bot\u00e3o para terminar a verifica\u00e7\u00e3o. A verifica\u00e7\u00e3o termina quando a verifica\u00e7\u00e3o for bem-sucedida ou o tempo de leitura exceder o tempo de leitura \u00fanico.</p>", "a[href=\"character.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#end-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de Volume<a class=\"headerlink\" href=\"#volume-settings\" title=\"Link to this heading\">#</a></h2><p>Digitalize o c\u00f3digo de configura\u00e7\u00e3o correspondente para ativar/desativar o prompt de som do scanner</p>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Restaurar configura\u00e7\u00f5es padr\u00e3o<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>Quando um erro desconhecido ocorre no scanner, voc\u00ea pode redefinir o scanner restaurando as configura\u00e7\u00f5es padr\u00e3o.</p>", "a[href=\"character.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>", "a[href=\"character.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Exterminador<a class=\"headerlink\" href=\"#terminator\" title=\"Link to this heading\">#</a></h1><h2>Iniciar Configura\u00e7\u00e3o<a class=\"headerlink\" href=\"#start-setup\" title=\"Link to this heading\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
